const items = $input.all();
if (!items.length) throw new Error('The topic feed returned no items');
const top = items[0].json;

// Google Trends carries an item picture; other feeds may not - Build Posts falls back to config imageUrl.
const picture = top['ht:picture'] || top['media:content'] || null;

return [{ json: {
  topic: top.title,
  context: (top.contentSnippet || top.content || '').slice(0, 500),
  link: top.link || '',
  picture,
} }];

const out = $input.first().json;
// The OpenAI node returns { message: { content } }; older/simplified shapes differ - handle them all.
let text = (out.message && out.message.content) || out.output || out.text || (out.choices && out.choices[0] && out.choices[0].message.content) || '';
if (typeof text !== 'string') text = JSON.stringify(text);

let caption = '';
let hashtags = '';
try {
  const match = text.match(/\{[\s\S]*\}/);
  const parsed = JSON.parse(match ? match[0] : text);
  caption = String(parsed.caption || '').trim();
  hashtags = String(parsed.hashtags || '').trim();
} catch (e) {
  caption = text.trim();
}
if (!caption) throw new Error('The model returned no caption');

const topic = $('Pick a Topic').first().json;
return [{ json: { caption, hashtags, picture: topic.picture } }];

const config = $('Configuration (EDIT ME)').first().json;
const draft = $('Parse the Draft').first().json;
const channels = $input.first().json.data || [];

const baseUrl = String(config.postStackUrl || '').replace(/\/+$/, '');
const wanted = String(config.channelIds || '').split(',').map((s) => s.trim()).filter(Boolean);
if (!wanted.length) throw new Error('channelIds in Configuration is empty');

const byId = new Map(channels.map((c) => [c.id, c]));
return wanted.map((id) => {
  const channel = byId.get(id);
  if (!channel) throw new Error(`Channel ${id} not found in PostStack - check channelIds`);
  return { json: {
    channelId: channel.id,
    platform: channel.platform,
    channelName: channel.display_name,
    caption: draft.caption,
    hashtags: draft.hashtags,
    imageUrl: draft.picture || config.imageUrl,
    createUrl: `${baseUrl}/api/v1/posts`,
  } };
});

const config = $('Configuration (EDIT ME)').first().json;
const baseUrl = String(config.postStackUrl || '').replace(/\/+$/, '');

return $input.all().map((item, i) => {
  const postId = item.json.data && item.json.data.id;
  if (!postId) throw new Error('Post creation did not return an id');
  const plan = $('Build Posts per Channel').all()[i].json;
  return { json: {
    publishUrl: `${baseUrl}/api/v1/posts/${postId}/publish`,
    channelId: plan.channelId,
    channelName: plan.channelName,
  } };
});
